			'X-Forwarded-For',
			'X-Client-IP',
			'X-Real-IP',
			'X-ProxyUser-Ip',
			'CF-Connecting-IP',
			'True-Client-IP',
			'REMOTE_ADDR',
		);
	}

	$client_addr = false;
	foreach ($http_addr_headers as $header) {
		if (!empty($_SERVER[$header])) {
			$header_ips = explode(',', $_SERVER[$header]);
